/**
 * CoopSystem — Manages player-to-character assignments and Navigator designation.
 * Supports 1–4 players. All player IDs are 1-based (1–4).
 * InputManager player IDs are 0-based (0–3) — use playerId-1 when indexing.
 *
 * @module CoopSystem
 */

import DebugLog from '../debug/DebugLog.js';
import EventBus from '../core/EventBus.js';
import CharacterSystem from './CharacterSystem.js';

const CoopSystem = {
  /**
   * Player-to-character assignments.
   * Key: playerId (1–4), Value: characterId (string) or null.
   * @type {{ 1: string|null, 2: string|null, 3: string|null, 4: string|null }}
   */
  _assignments: { 1: null, 2: null, 3: null, 4: null },

  /**
   * Which player is the Navigator (controls world map movement).
   * Always P1 by default.
   * @type {number}
   */
  _navigatorPlayer: 1,

  /**
   * How many players are currently active (1–4).
   * @type {number}
   */
  _playerCount: 1,

  // ─── Assignment API ───────────────────────────────────────────────────────

  /**
   * Assign a character to a player slot.
   * A character may only be assigned to one player at a time; any prior
   * assignment of that character to another player is cleared first.
   *
   * @param {number} playerId — 1–4
   * @param {string|null} characterId — Pass null to unassign the slot.
   * @returns {boolean} true on success, false if validation failed.
   */
  assignCharacter(playerId, characterId) {
    if (playerId < 1 || playerId > 4) {
      DebugLog.warn(`[coop] assignCharacter: invalid playerId ${playerId}`);
      return false;
    }

    if (characterId !== null) {
      // Verify the character exists
      const char = CharacterSystem.getById(characterId);
      if (!char) {
        DebugLog.warn(`[coop] assignCharacter: unknown characterId "${characterId}"`);
        return false;
      }

      // Remove any existing assignment of this character to another player
      for (const pid of [1, 2, 3, 4]) {
        if (pid !== playerId && this._assignments[pid] === characterId) {
          this._assignments[pid] = null;
          DebugLog.info(`[coop] assignCharacter: cleared P${pid} (was holding "${characterId}")`);
        }
      }
    }

    const prev = this._assignments[playerId];
    this._assignments[playerId] = characterId;

    DebugLog.info(
      `[coop] assignCharacter; player=${playerId} ` +
      `character=${characterId ?? 'null'} prev=${prev ?? 'null'}`
    );

    EventBus.emit('coop:assigned', {
      playerId,
      characterId,
      character: characterId ? CharacterSystem.getById(characterId) : null,
    });

    return true;
  },

  /**
   * Set which player is the Navigator (controls world map movement).
   * @param {number} playerId — 1–4
   */
  setNavigator(playerId) {
    if (playerId < 1 || playerId > 4) {
      DebugLog.warn(`[coop] setNavigator: invalid playerId ${playerId}`);
      return;
    }
    this._navigatorPlayer = playerId;
    DebugLog.info(`[coop] setNavigator; player=${playerId}`);
    EventBus.emit('coop:navigatorChanged', { playerId });
  },

  // ─── Queries ──────────────────────────────────────────────────────────────

  /**
   * Get the character object assigned to a player.
   * @param {number} playerId — 1–4
   * @returns {object|null}
   */
  getCharacterForPlayer(playerId) {
    const id = this._assignments[playerId];
    return id ? CharacterSystem.getById(id) : null;
  },

  /**
   * Get which player (1–4) controls a given character.
   * Returns null if the character is not assigned to any player.
   * @param {string} characterId
   * @returns {number|null}
   */
  getPlayerForCharacter(characterId) {
    for (const [pid, cid] of Object.entries(this._assignments)) {
      if (cid === characterId) return parseInt(pid, 10);
    }
    return null;
  },

  /**
   * Is it this player's turn in combat?
   * Reads from window.__combatSystem optionally to avoid a hard dependency.
   * @param {number} playerId — 1–4
   * @returns {boolean}
   */
  isPlayerTurn(playerId) {
    const combatState = window.__combatSystem?.getState?.();
    if (!combatState) return false;

    const currentCharId = combatState.currentTurn?.characterId ?? null;
    if (!currentCharId) return false;

    return this._assignments[playerId] === currentCharId;
  },

  /**
   * Is the given player currently the Navigator?
   * @param {number} playerId — 1–4
   * @returns {boolean}
   */
  isNavigator(playerId) {
    return this._navigatorPlayer === playerId;
  },

  /**
   * Auto-assign all characters in CharacterSystem to players in order.
   * P1 gets the first character, P2 the second, etc., up to 4.
   * Called when the party is finalized in the party builder.
   */
  autoAssign() {
    const chars = CharacterSystem.getAll();

    // Reset all slots before assigning
    this._assignments = { 1: null, 2: null, 3: null, 4: null };

    chars.forEach((char, i) => {
      if (i < 4) {
        this.assignCharacter(i + 1, char.id);
      }
    });

    DebugLog.info(`[coop] autoAssign; assigned ${Math.min(chars.length, 4)} character(s)`);
  },

  // ─── Player count ─────────────────────────────────────────────────────────

  /**
   * Get the number of active players.
   * @returns {number} 1–4
   */
  getPlayerCount() {
    return this._playerCount;
  },

  /**
   * Set the number of active players. Clamped to 1–4.
   * @param {number} n
   */
  setPlayerCount(n) {
    this._playerCount = Math.max(1, Math.min(4, n));
    DebugLog.info(`[coop] setPlayerCount; count=${this._playerCount}`);
    EventBus.emit('coop:playerCountChanged', { playerCount: this._playerCount });
  },

  // ─── Accessors ────────────────────────────────────────────────────────────

  /**
   * Get a shallow copy of the current assignments map.
   * @returns {{ 1: string|null, 2: string|null, 3: string|null, 4: string|null }}
   */
  getAssignments() {
    return { ...this._assignments };
  },

  /**
   * Get the current Navigator player ID.
   * @returns {number}
   */
  getNavigator() {
    return this._navigatorPlayer;
  },

  // ─── Serialization ────────────────────────────────────────────────────────

  /**
   * Serialize CoopSystem state for saving.
   * @returns {{ assignments: object, navigator: number, playerCount: number }}
   */
  serialize() {
    return {
      assignments: { ...this._assignments },
      navigator: this._navigatorPlayer,
      playerCount: this._playerCount,
    };
  },

  /**
   * Restore CoopSystem state from save data.
   * @param {{ assignments: object, navigator: number, playerCount: number }} data
   */
  deserialize(data) {
    if (!data) return;

    if (data.assignments) {
      this._assignments = { 1: null, 2: null, 3: null, 4: null };
      for (const pid of [1, 2, 3, 4]) {
        const cid = data.assignments[pid] ?? null;
        if (cid !== null) {
          this._assignments[pid] = cid;
        }
      }
    }

    if (typeof data.navigator === 'number') {
      this._navigatorPlayer = data.navigator;
    }

    if (typeof data.playerCount === 'number') {
      this._playerCount = Math.max(1, Math.min(4, data.playerCount));
    }

    DebugLog.info(
      `[coop] deserialize; navigator=${this._navigatorPlayer} ` +
      `playerCount=${this._playerCount}`
    );
  },

  /**
   * Reset CoopSystem to initial state.
   * Called when returning to main menu or starting a new game.
   */
  reset() {
    this._assignments = { 1: null, 2: null, 3: null, 4: null };
    this._navigatorPlayer = 1;
    this._playerCount = 1;
    DebugLog.info('[coop] reset');
  },
};

export default CoopSystem;
